1	<script>
2	  const KEYS = [
3	    { id: 'k1', angle: 20 },
4	    { id: 'k2', angle: 70 },
5	    { id: 'k3', angle: 110 },
6	    { id: 'k4', angle: 160 },
7	  ];
8	
9	  const MIN = 0;
10	  const MAX = 360;
11	  const STEP = 5;
12	  const CX = 150;
13	  const CY = 150;
14	  const R = 108;
15	  const TRACK_H = 150;
16	
17	  let queryAngle = $state(90);
18	  let sliderEl = $state(null);
19	  let dragging = $state(false);
20	
21	  function clamp(v) {
22	    return Math.max(MIN, Math.min(MAX, v));
23	  }
24	
25	  function toRad(deg) {
26	    return (deg * Math.PI) / 180;
27	  }
28	
29	  function pointOnCircle(angleDeg, radius) {
30	    const rad = toRad(angleDeg);
31	    return {
32	      x: CX + radius * Math.cos(rad),
33	      y: CY - radius * Math.sin(rad),
34	    };
35	  }
36	
37	  function labelPoint(angleDeg) {
38	    return pointOnCircle(angleDeg, R + 24);
39	  }
40	
41	  function arrowPoints(angleDeg) {
42	    const tip = pointOnCircle(angleDeg, R);
43	    const rad = toRad(angleDeg);
44	    const dx = Math.cos(rad);
45	    const dy = -Math.sin(rad);
46	    const px = -dy;
47	    const py = dx;
48	    const size = 15;
49	    const half = 6.5;
50	    const baseX = tip.x - dx * size;
51	    const baseY = tip.y - dy * size;
52	    const leftX = baseX + px * half;
53	    const leftY = baseY + py * half;
54	    const rightX = baseX - px * half;
55	    const rightY = baseY - py * half;
56	    return `${tip.x},${tip.y} ${leftX},${leftY} ${rightX},${rightY}`;
57	  }
58	
59	  function fmt(n) {
60	    const v = Math.abs(n) < 0.005 ? 0 : n;
61	    return v.toFixed(2);
62	  }
63	
64	  function barHeight(score) {
65	    return Math.abs(score) * (TRACK_H / 2);
66	  }
67	
68	  function barTop(score) {
69	    const h = barHeight(score);
70	    return score >= 0 ? TRACK_H / 2 - h : TRACK_H / 2;
71	  }
72	
73	  let queryTip = $derived(pointOnCircle(queryAngle, R));
74	
75	  let scores = $derived.by(() => {
76	    const raw = KEYS.map((k) => {
77	      const diff = toRad(queryAngle - k.angle);
78	      return { id: k.id, angle: k.angle, score: Math.cos(diff) };
79	    });
80	    const max = Math.max(...raw.map((r) => r.score));
81	    return raw.map((r) => ({ ...r, leading: r.score >= max - 0.0001 }));
82	  });
83	
84	  function setAngleFromClient(clientX, clientY) {
85	    if (!sliderEl) return;
86	    const rect = sliderEl.getBoundingClientRect();
87	    const cx = rect.left + rect.width / 2;
88	    const cy = rect.top + rect.height / 2;
89	    const dx = clientX - cx;
90	    const dy = cy - clientY;
91	    let angle = (Math.atan2(dy, dx) * 180) / Math.PI;
92	    if (angle < 0) angle += 360;
93	    queryAngle = clamp(Math.round(angle));
94	  }
95	
96	  function onPointerDown(e) {
97	    dragging = true;
98	    if (sliderEl && sliderEl.setPointerCapture) {
99	      try {
100	        sliderEl.setPointerCapture(e.pointerId);
101	      } catch (err) {
102	        /* ignore */
103	      }
104	    }
105	    setAngleFromClient(e.clientX, e.clientY);
106	  }
107	
108	  function onPointerMove(e) {
109	    if (!dragging) return;
110	    setAngleFromClient(e.clientX, e.clientY);
111	  }
112	
113	  function endDrag(e) {
114	    dragging = false;
115	    if (sliderEl && sliderEl.releasePointerCapture && e && e.pointerId != null) {
116	      try {
117	        sliderEl.releasePointerCapture(e.pointerId);
118	      } catch (err) {
119	        /* ignore */
120	      }
121	    }
122	  }
123	
124	  function onKeydown(e) {
125	    let next = queryAngle;
126	    if (e.key === 'ArrowRight' || e.key === 'ArrowUp') {
127	      next = clamp(queryAngle + STEP);
128	    } else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') {
129	      next = clamp(queryAngle - STEP);
130	    } else if (e.key === 'Home') {
131	      next = MIN;
132	    } else if (e.key === 'End') {
133	      next = MAX;
134	    } else {
135	      return;
136	    }
137	    e.preventDefault();
138	    queryAngle = next;
139	  }
140	</script>
141	
142	<div class="qk-root" data-interactive="qk-explorer">
143	  <p class="instruction">Turn q until it lines up with a key.</p>
144	
145	  <div
146	    class="diagram"
147	    role="slider"
148	    tabindex="0"
149	    bind:this={sliderEl}
150	    aria-valuemin={MIN}
151	    aria-valuemax={MAX}
152	    aria-valuenow={queryAngle}
153	    aria-valuetext={`${queryAngle} degrees`}
154	    aria-label="Query angle in degrees"
155	    onpointerdown={onPointerDown}
156	    onpointermove={onPointerMove}
157	    onpointerup={endDrag}
158	    onpointercancel={endDrag}
159	    onkeydown={onKeydown}
160	  >
161	    <svg viewBox="0 0 300 300" aria-hidden="true">
162	      <circle class="guide" cx={CX} cy={CY} r={R} />
163	      <circle class="center-dot" cx={CX} cy={CY} r="3.5" />
164	
165	      {#each scores as s (s.id)}
166	        {@const tip = pointOnCircle(s.angle, R)}
167	        {@const lbl = labelPoint(s.angle)}
168	        <line
169	          class="key-line"
170	          class:leading={s.leading}
171	          x1={CX}
172	          y1={CY}
173	          x2={tip.x}
174	          y2={tip.y}
175	        />
176	        <circle class="key-dot" class:leading={s.leading} cx={tip.x} cy={tip.y} r="5" />
177	        <text class="label-text key-label" x={lbl.x} y={lbl.y} text-anchor="middle" dominant-baseline="middle">
178	          {s.id}
179	        </text>
180	      {/each}
181	
182	      <line class="query-line" x1={CX} y1={CY} x2={queryTip.x} y2={queryTip.y} />
183	      <polygon class="query-arrow" points={arrowPoints(queryAngle)} />
184	      {#each [labelPoint(queryAngle)] as lbl}
185	        <text class="label-text query-label" x={lbl.x} y={lbl.y} text-anchor="middle" dominant-baseline="middle">
186	          q
187	        </text>
188	      {/each}
189	    </svg>
190	  </div>
191	
192	  <p class="angle-readout">q = <span class="angle-value">{queryAngle}</span> deg</p>
193	
194	  <div class="scores-row">
195	    {#each scores as s (s.id)}
196	      <div class="score-col">
197	        <span class="score-label">{s.id}</span>
198	        <div class="bar-track">
199	          <div class="baseline"></div>
200	          <div
201	            class="bar-fill"
202	            class:leading={s.leading}
203	            style={`top:${barTop(s.score)}px; height:${barHeight(s.score)}px;`}
204	          ></div>
205	        </div>
206	        <span class="score-value" class:leading={s.leading}>{fmt(s.score)}</span>
207	      </div>
208	    {/each}
209	  </div>
210	</div>
211	
212	<style>
213	  .qk-root,
214	  .qk-root * {
215	    box-sizing: border-box;
216	  }
217	
